Auth Event Schemas (Avro)
=========================
LoginEvent {
  user_id: string (UUID)
  provider: enum {google, saml, local}
  ip_address: string
  user_agent: string
  timestamp: long (millis)
  mfa_used: boolean
}

LogoutEvent {
  user_id: string (UUID)
  session_id: string (UUID)
  reason: enum {user_initiated, timeout, admin_revoke}
  timestamp: long (millis)
}
